import './NossaMissao.css'

const NossaMissao = () => {
    return (
        <section id="nossa-missao">


            <Cards
                title={"Nossa Missão"}
                desc={"jjjjjjjjjjjjjjjjjjjjjjjjjjjasdasdasdssssssssssssjjjjjjjjjjjjjjjjjjjjjjjjjjjjjjjj"}
            />

            <Cards
                title={"Valores"}
            />

        </section>
    )
}

const Cards = ({ title, desc }) => {
    return (
        <div className="nm-cards">
            <h3>{title}</h3>
            <p>{desc}</p>
        </div>
    )
}

export default NossaMissao
